from flask import Flask, request, jsonify
import sqlite3
import random
import string
import smtplib

app = Flask(__name__)

def generate_token():
    return ''.join(random.choices(string.ascii_letters + string.digits, k=20))

def store_token(email, token):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE IF NOT EXISTS password_reset (email TEXT, token TEXT)')
    cursor.execute('DELETE FROM password_reset WHERE email = ?', (email,))
    cursor.execute('INSERT INTO password_reset (email, token) VALUES (?, ?)', (email, token))
    conn.commit()
    conn.close()

def send_email(email, token):
    reset_link = f"http://example.com/reset_password?token={token}"
    with smtplib.SMTP('localhost') as server:
        server.sendmail('noreply@example.com', email, f'Subject: Password Reset\n\nClick the following link to reset your password: {reset_link}')

@app.route('/api/password_reset', methods=['POST'])
def password_reset():
    data = request.json
    email = data.get('email')
    if email:
        token = generate_token()
        store_token(email, token)
        send_email(email, token)
        return jsonify({"message": "Password reset link sent"}), 200
    return jsonify({"error": "Email required"}), 400

if __name__ == '__main__':
    app.run(debug=True)